// ============================================================================
// STAT BADGE
// ============================================================================

interface StatBadgeProps {
  value: string;
  label: string;
  variant?: 'default' | 'success' | 'warning' | 'destructive';
}

export function StatBadge({ value, label, variant = 'default' }: StatBadgeProps) {
  const colorClass = variant === 'success' ? 'text-green-500' : 
                     variant === 'warning' ? 'text-amber-500' : 
                     variant === 'destructive' ? 'text-red-500' : 'text-foreground';
  
  return (
    <div className="flex flex-col items-start min-w-[70px]">
      <div className="text-[10px] text-muted-foreground uppercase tracking-wider font-medium mb-0.5">{label}</div>
      <div className={`text-sm font-mono tabular-nums font-semibold ${colorClass}`}>{value}</div>
    </div>
  );
}

// ============================================================================
// DEMAND INDICATOR
// ============================================================================

interface DemandIndicatorProps {
  label: string;
  demand: number;
  color: string;
}

export function DemandIndicator({ label, demand, color }: DemandIndicatorProps) {
  const height = Math.abs(demand) / 2;
  const isPositive = demand >= 0;
  
  return (
    <div className="flex flex-col items-center gap-1">
      <span className={`text-[10px] font-bold ${color}`}>{label}</span>
      <div className="w-3 h-8 bg-secondary relative rounded-sm overflow-hidden">
        <div className="absolute left-0 right-0 top-1/2 h-px bg-border" />
        <div
          className={`absolute left-0 right-0 ${color.replace('text-', 'bg-')}`}
          style={{
            height: `${height}%`,
            top: isPositive ? `${50 - height}%` : '50%',
          }}
        />
      </div>
    </div>
  );
}

// ============================================================================
// MINI STAT (for StatsPanel)
// ============================================================================

interface MiniStatProps {
  icon: React.ReactNode;
  label: string;
  value: number;
}

export function MiniStat({ icon, label, value }: MiniStatProps) {
  const color = value >= 70 ? 'text-green-500' : value >= 40 ? 'text-amber-500' : 'text-red-500';
  return (
    <div className="flex items-center gap-2">
      <span className="text-muted-foreground">{icon}</span>
      <span className="text-muted-foreground">{label}</span>
      <span className={`font-mono ${color}`}>{Math.round(value)}%</span>
    </div>
  );
}

function clampPercent(value: number): number {
  if (!Number.isFinite(value)) return 0;
  return Math.max(0, Math.min(100, value));
}

function formatCompactNumber(value: number): string {
  if (!Number.isFinite(value)) return '0';
  const abs = Math.abs(value);
  const sign = value < 0 ? '-' : '';

  if (abs >= 1_000_000_000_000) return `${sign}${(abs / 1_000_000_000_000).toFixed(1)}t`;
  if (abs >= 1_000_000_000) return `${sign}${(abs / 1_000_000_000).toFixed(1)}b`;
  if (abs >= 1_000_000) return `${sign}${(abs / 1_000_000).toFixed(1)}m`;
  if (abs >= 1_000) return `${sign}${(abs / 1_000).toFixed(1)}k`;
  return `${value}`;
}

function formatCompactCurrency(value: number): string {
  return `$${formatCompactNumber(value)}`;
}

// ============================================================================
// STATS PANEL
// ============================================================================

export const StatsPanel = React.memo(function StatsPanel() {
  const { state, investorSession } = useGame();
  const { stats } = state;
  const m = useMessages();
  const statsWithVc = (stats ?? {}) as Partial<typeof stats> & { valuation?: number; headcount?: number };
  const toNum = (value: unknown, fallback = 0): number =>
    typeof value === 'number' && Number.isFinite(value) ? value : fallback;
  const money = toNum(statsWithVc.money, 0);
  const income = toNum(statsWithVc.income, 0);
  const expenses = toNum(statsWithVc.expenses, 0);
  const population = toNum(statsWithVc.population, 0);
  const jobs = toNum(statsWithVc.jobs, 0);
  const demand = {
    residential: toNum(statsWithVc.demand?.residential, 0),
    commercial: toNum(statsWithVc.demand?.commercial, 0),
    industrial: toNum(statsWithVc.demand?.industrial, 0),
  };

  const pmfSignalCalculated = clampPercent(
    toNum(statsWithVc.happiness, 50) * 0.45 +
      toNum(statsWithVc.education, 30) * 0.25 +
      ((demand.commercial + 100) / 2) * 0.2 +
      8,
  );
  const growthMomentumCalculated = clampPercent(
    ((income - expenses) / Math.max(Math.abs(income), 1)) * 35 + 50 + demand.commercial * 0.15 + 10,
  );
  const burnMultipleRaw = income > 0 ? expenses / income : expenses > 0 ? 3 : 1;
  const burnDisciplineCalculated = clampPercent(100 - burnMultipleRaw * 30 + 9);
  const investorConfidenceCalculated = clampPercent(
    (money > 0 ? 46 : 30) +
      demand.commercial * 0.2 +
      demand.industrial * 0.12 +
      (income > expenses ? 10 : -6) +
      8
  );
  const hiringVelocityCalculated = clampPercent(
    (jobs / Math.max(population, 1)) * 70 +
      demand.residential * 0.25 +
      demand.commercial * 0.12 +
      7
  );
  const pmfSignal = investorSession
    ? clampPercent(investorSession.stats.pmfSignalPercentile)
    : pmfSignalCalculated;
  const growthMomentum = investorSession
    ? clampPercent(investorSession.stats.growthMomentumPercentile)
    : growthMomentumCalculated;
  const burnDiscipline = investorSession
    ? clampPercent(investorSession.stats.burnDisciplinePercentile)
    : burnDisciplineCalculated;
  const investorConfidence = investorSession
    ? clampPercent(investorSession.stats.investorConfidencePercentile)
    : investorConfidenceCalculated;
  const hiringVelocity = investorSession
    ? clampPercent(investorSession.stats.hiringVelocityPercentile)
    : hiringVelocityCalculated;
  
  return (
    <div className="h-8 bg-secondary/50 border-b border-border flex items-center justify-center gap-8 text-xs">
      <MiniStat icon={<HappyIcon size={12} />} label={String(m(UI_LABELS.pmfSignal))} value={pmfSignal} />
      <MiniStat icon={<EducationIcon size={12} />} label={String(m(UI_LABELS.growthMomentum))} value={growthMomentum} />
      <MiniStat icon={<EnvironmentIcon size={12} />} label={String(m(UI_LABELS.burnDiscipline))} value={burnDiscipline} />
      <MiniStat icon={<HealthIcon size={12} />} label={String(m(UI_LABELS.investorConfidence))} value={investorConfidence} />
      <MiniStat icon={<SafetyIcon size={12} />} label={String(m(UI_LABELS.hiringVelocity))} value={hiringVelocity} />
    </div>
  );
});

// ============================================================================
// TOP BAR
// ============================================================================

export const TopBar = React.memo(function TopBar() {
  const {
    state,
    setSpeed,
    setTaxRate,
    setCompetitionDegree,
    visualHour,
    investorSession,
  } = useGame();
  const { stats, year, month, day, speed, taxRate, cityName, competitionDegree } = state;
  const m = useMessages();
  const statsWithVc = (stats ?? {}) as Partial<typeof stats> & { valuation?: number; headcount?: number };
  const toNum = (value: unknown, fallback = 0): number =>
    typeof value === 'number' && Number.isFinite(value) ? value : fallback;
  const valuation = investorSession
    ? investorSession.stats.ecosystemValue
    : toNum(statsWithVc.valuation, toNum(statsWithVc.population, 0));
  const headcount = investorSession
    ? investorSession.stats.operatorHeadcount
    : toNum(statsWithVc.headcount, toNum(statsWithVc.jobs, 0));
  const money = investorSession ? investorSession.stats.dryPowder : toNum(statsWithVc.money, 0);
  const income = toNum(statsWithVc.income, 0);
  const expenses = toNum(statsWithVc.expenses, 0);
  const netBurn = investorSession ? investorSession.stats.netBurn : income - expenses;
  const runwayMonths = investorSession
    ? investorSession.stats.runwayMonths
    : expenses > 0
      ? Math.max(0, money / expenses)
      : 99;
  const demand = {
    commercial: toNum(statsWithVc.demand?.commercial, 0),
    industrial: toNum(statsWithVc.demand?.industrial, 0),
  };
  const dealFlow = investorSession
    ? investorSession.stats.dealFlow
    : Math.max(0, Math.round((demand.commercial + demand.industrial + 220) / 28));
  const cityLabel = investorSession
    ? investorSession.profile.name
    : cityName === 'IsoCity'
      ? 'ISOBUSINESS'
      : cityName;
  
  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  const formattedDate = `${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}-${year}`;
  
  // Safety check for pendingOpportunities
  const pendingOpportunitiesArr = (state as any).pendingOpportunities || [];
  const dealFlowDerived = Math.max(0, Math.round((demand.commercial + demand.industrial + 220) / 28));
  const pendingDealFlow = (pendingOpportunitiesArr.length || 0) || dealFlowDerived;
  const finalDealFlow = investorSession ? investorSession.stats.dealFlow : pendingDealFlow;
  const dataMode = investorSession ? (investorSession.source === 'api' ? 'SQL' : 'FALLBACK') : 'N/A';
  const llmMode = (state.llmRouterMode || 'unknown').toLowerCase();
  
  return (
    <div className="h-14 bg-card border-b border-border flex items-center justify-between px-4">
      <div className="flex items-center gap-6">
        <div>
          <div className="flex items-center gap-2">
            <h1 className="text-foreground font-semibold text-sm">{cityLabel}</h1>
          </div>
          <div className="flex items-center gap-2 text-muted-foreground text-xs font-mono tabular-nums">
            <Tooltip>
              <TooltipTrigger asChild>
                <span>{monthNames[month - 1]} {year}</span>
              </TooltipTrigger>
              <TooltipContent>
                <p>{formattedDate}</p>
              </TooltipContent>
            </Tooltip>
            <TimeOfDayIcon hour={visualHour} />
            {investorSession && (
              <span className="text-[10px] uppercase tracking-wide">
                #{investorSession.profile.monthRank} · {investorSession.profile.investorType} · {investorSession.profile.hq}
              </span>
            )}
            <span
              className={`rounded px-1.5 py-0.5 text-[9px] font-semibold tracking-wide ${
                dataMode === 'SQL' ? 'bg-emerald-500/20 text-emerald-300' : 'bg-amber-500/20 text-amber-300'
              }`}
            >
              DATA: {dataMode}
            </span>
            <span
              className={`rounded px-1.5 py-0.5 text-[9px] font-semibold tracking-wide ${
                llmMode === 'brev'
                  ? 'bg-cyan-500/20 text-cyan-300'
                  : llmMode === 'bedrock'
                    ? 'bg-violet-500/20 text-violet-300'
                    : 'bg-slate-500/20 text-slate-300'
              }`}
            >
              LLM: {llmMode}
            </span>
          </div>
        </div>
        
        <div className="flex items-center gap-0 bg-secondary rounded-md p-0">
          {[0, 1, 2, 3].map(s => (
            <Button
              key={s}
              onClick={() => setSpeed(s as 0 | 1 | 2 | 3)}
              variant={speed === s ? 'default' : 'ghost'}
              size="icon-sm"
              className="h-7 w-7 p-0 m-0"
              title={s === 0 ? 'Pause' : s === 1 ? 'Normal' : s === 2 ? 'Fast' : 'Very Fast'}
            >
              {s === 0 ? <PauseIcon size={12} /> : 
               s === 1 ? <PlayIcon size={12} /> : 
               s === 2 ? (
                 <div className="flex items-center -space-x-[5px]">
                   <PlayIcon size={12} />
                   <PlayIcon size={12} />
                 </div>
               ) :
               <div className="flex items-center -space-x-[7px]">
                 <PlayIcon size={12} />
                 <PlayIcon size={12} />
                 <PlayIcon size={12} />
               </div>}
            </Button>
          ))}
        </div>
      </div>
      
      <div className="flex items-center gap-3">
        <StatBadge 
          value={formatCompactCurrency(valuation)}
          label={String(m(UI_LABELS.ecosystemValue))}
        />
        <StatBadge value={formatCompactNumber(headcount)} label={String(m(UI_LABELS.operatorHeadcount))} />
        <StatBadge 
          value={formatCompactCurrency(money)} 
          label={String(m(UI_LABELS.dryPowder))}
          variant={money < 0 ? 'destructive' : money < 1_000_000 ? 'warning' : 'success'}
        />
      </div>
      
      <div className="flex items-center gap-2">
        <StatBadge value={formatCompactCurrency(netBurn)} label={String(m(UI_LABELS.netBurn))} variant={netBurn >= 0 ? 'success' : 'destructive'} />
        <StatBadge value={`${runwayMonths.toFixed(1)}m`} label={String(m(UI_LABELS.runway))} variant={runwayMonths < 6 ? 'destructive' : runwayMonths < 12 ? 'warning' : 'success'} />
        <StatBadge
          value={finalDealFlow.toString()}
          label={String(m(UI_LABELS.dealFlow))}
          variant={finalDealFlow >= 8 ? 'success' : finalDealFlow >= 4 ? 'warning' : 'default'}
        />
        
        <Separator orientation="vertical" className="h-8" />
        
        <div className="flex items-center gap-1.5">
          <span className="text-muted-foreground text-xs">{m(UI_LABELS.policyLeverage)}</span>
          <Slider
            value={[state.competitionDegree ?? 32]}
            onValueChange={(value) => setCompetitionDegree(value[0])}
            min={0}
            max={100}
            step={1}
            className="w-24"
          />
          <span className="text-foreground text-xs font-mono tabular-nums w-8 text-right">{state.competitionDegree ?? 32}%</span>
        </div>
        
        <Separator orientation="vertical" className="h-8" />
        
        <LanguageSelector iconOnly={false} variant="ghost" iconSize={14} />
      </div>
    </div>
  );
});
