'use client';

import React from 'react';
import { msg } from 'gt-next';
import { useMessages } from 'gt-next';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { CloseIcon, AdvisorIcon, MoneyIcon, JobsIcon, EnvironmentIcon } from '@/components/ui/Icons';
import { OverlayMode } from './types';
import { getOverlayButtonClass } from './overlays';

// ============================================================================
// Types
// ============================================================================

export interface OverlayModeToggleProps {
  overlayMode: OverlayMode;
  setOverlayMode: (mode: OverlayMode) => void;
}

// ============================================================================
// Icon Mapping
// ============================================================================

const LLM_OVERLAY_MODES: OverlayMode[] = ['none', 'swarm_investor_company', 'swarm_investor_investor', 'swarm_company_company', 'swarm_employee_leadership'];

const LENS_BUTTONS: Array<{ mode: OverlayMode; icon: React.ReactNode; hoverLabel: string }> = [
  { mode: 'none', icon: <CloseIcon size={14} />, hoverLabel: 'No Lens' },
  { mode: 'swarm_investor_company', icon: <AdvisorIcon size={14} />, hoverLabel: 'LLM Calls: Investors <-> CEO/Founder' },
  { mode: 'swarm_investor_investor', icon: <MoneyIcon size={14} />, hoverLabel: 'LLM Calls: Investors <-> Investors' },
  { mode: 'swarm_company_company', icon: <EnvironmentIcon size={14} />, hoverLabel: 'LLM Calls: Companies <-> Companies' },
  { mode: 'swarm_employee_leadership', icon: <JobsIcon size={14} />, hoverLabel: 'LLM Calls: Employees <-> CEO/Founder' },
];

const LENS_LABEL_BY_MODE: Record<OverlayMode, string> = {
  none: 'No Lens',
  power: 'No Lens',
  water: 'No Lens',
  fire: 'No Lens',
  police: 'No Lens',
  health: 'No Lens',
  education: 'No Lens',
  subway: 'No Lens',
  swarm_investor_company: 'LLM Calls: Investors <-> CEO/Founder',
  swarm_investor_investor: 'LLM Calls: Investors <-> Investors',
  swarm_company_company: 'LLM Calls: Companies <-> Companies',
  swarm_employee_leadership: 'LLM Calls: Employees <-> CEO/Founder',
};

// ============================================================================
// Translatable Labels
// ============================================================================

const VIEW_OVERLAY_LABEL = msg('LLM Call Lens');

// ============================================================================
// Component
// ============================================================================

/**
 * LLM call lens toggle component.
 * Shows only communication overlays for present-tick swarm channels.
 */
export const OverlayModeToggle = React.memo(function OverlayModeToggle({
  overlayMode,
  setOverlayMode,
}: OverlayModeToggleProps) {
  const m = useMessages();
  const [hoveredMode, setHoveredMode] = React.useState<OverlayMode | null>(null);
  const hoverLabel = hoveredMode ? LENS_LABEL_BY_MODE[hoveredMode] : LENS_LABEL_BY_MODE[overlayMode];

  React.useEffect(() => {
    if (!LLM_OVERLAY_MODES.includes(overlayMode)) {
      setOverlayMode('none');
    }
  }, [overlayMode, setOverlayMode]);
  
  return (
    <Card className="fixed bottom-4 left-[240px] p-2 shadow-lg bg-card/90 border-border/70 z-50">
      <div className="text-[10px] uppercase tracking-[0.12em] text-muted-foreground font-semibold mb-2">
        {m(VIEW_OVERLAY_LABEL)}
      </div>
      <div className="relative left-[-71px] flex gap-1">
        {LENS_BUTTONS.map(({ mode, icon, hoverLabel: buttonHoverLabel }) => {
          const isActive = overlayMode === mode;
          
          return (
            <Button
              key={mode}
              variant={isActive ? 'default' : 'ghost'}
              size="sm"
              onClick={() => setOverlayMode(mode)}
              onMouseEnter={() => setHoveredMode(mode)}
              onMouseLeave={() => setHoveredMode(null)}
              className={`h-8 px-3 ${getOverlayButtonClass(mode, isActive)}`}
              title={buttonHoverLabel}
            >
              {icon}
            </Button>
          );
        })}
      </div>
      <div className="mt-1 min-h-[14px] text-[10px] text-muted-foreground">
        {hoverLabel}
      </div>
    </Card>
  );
});
